      "olymp.cm.toc.title": "In this article",
      "olymp.cm.h1": "Common Mistakes and How to Avoid Them",
      "olymp.cm.lead": "Learn from the most frequent errors that cost points in economics olympiads and develop systematic strategies to prevent them.",
      "olymp.cm.s1.h2": "Conceptual Misunderstandings and Theoretical Errors",
      "olymp.cm.s2.h2": "Mathematical and Calculation Errors",
      "olymp.cm.s3.h2": "Time Management and Strategic Errors",
